import 'package:flutter_test/flutter_test.dart'; import 'package:googlepro/features/webrtc/service/bandwidth_estimator.dart'; import 'package:googlepro/features/webrtc/model/webrtc_state.dart'; void main() { group('BandwidthEstimator', () { test('initial estimate is 2000 kbps', () { final est = BandwidthEstimator(); expect(est.estimatedKbps, 2000); }); test('reduces bitrate on high packet loss', () { final est = BandwidthEstimator(); const badStats = WebRtcStats(packetLoss: 0.15, latencyMs: 600); est.updateFromStats(badStats); expect(est.estimatedKbps, lessThan(2000)); }); test('increases bitrate on good connection', () { final est = BandwidthEstimator(); const goodStats = WebRtcStats(packetLoss: 0.01, latencyMs: 50); est.updateFromStats(goodStats); expect(est.estimatedKbps, greaterThanOrEqualTo(2000)); }); }); }